445 vputils::getRecipesForUncountableExit(VPlan &Plan,
446                                       SmallVectorImpl<VPRecipeBase *> &Recipes,
447                                       SmallVectorImpl<VPRecipeBase *> &GEPs) {
448   // Given a VPlan like the following (just including the recipes contributing
449   // to loop control exiting here, not the actual work), we're looking to match
450   // the recipes contributing to the uncountable exit condition comparison
451   // (here, vp<%4>) back to either live-ins or the address nodes for the load
452   // used as part of the uncountable exit comparison so that we can copy them
453   // to a preheader and rotate the address in the loop to the next vector
454   // iteration.
455   //
456   // Currently, the address of the load is restricted to a GEP with 2 operands
457   // and a live-in base address. This constraint may be relaxed later.
458   //
459   // VPlan ' for UF>=1' {
460   // Live-in vp<%0> = VF
461   // Live-in ir<64> = original trip-count
462   //
463   // entry:
464   // Successor(s): preheader, vector.ph
465   //
466   // vector.ph:
467   // Successor(s): vector loop
468   //
469   // <x1> vector loop: {
470   //   vector.body:
471   //     EMIT vp<%2> = CANONICAL-INDUCTION ir<0>
472   //     vp<%3> = SCALAR-STEPS vp<%2>, ir<1>, vp<%0>
473   //     CLONE ir<%ee.addr> = getelementptr ir<0>, vp<%3>
474   //     WIDEN ir<%ee.load> = load ir<%ee.addr>
475   //     WIDEN vp<%4> = icmp eq ir<%ee.load>, ir<0>
476   //     EMIT vp<%5> = any-of vp<%4>
477   //     EMIT vp<%6> = add vp<%2>, vp<%0>
478   //     EMIT vp<%7> = icmp eq vp<%6>, ir<64>
479   //     EMIT branch-on-two-conds vp<%5>, vp<%7>
480   //   No successors
481   // }
482   // Successor(s): early.exit, middle.block
483   //
484   // middle.block:
485   // Successor(s): preheader
486   //
487   // preheader:
488   // No successors
489   // }
490 
491   // Find the uncountable loop exit condition.
492   auto *Region = Plan.getVectorLoopRegion();
493   VPValue *UncountableCondition = nullptr;
494   if (!match(Region->getExitingBasicBlock()->getTerminator(),
495              m_BranchOnTwoConds(m_AnyOf(m_VPValue(UncountableCondition)),
496                                 m_VPValue())))
497     return std::nullopt;
498 
499   SmallVector<VPValue *, 4> Worklist;
500   Worklist.push_back(UncountableCondition);
501   while (!Worklist.empty()) {
502     VPValue *V = Worklist.pop_back_val();
503 
504     // Any value defined outside the loop does not need to be copied.
505     if (V->isDefinedOutsideLoopRegions())
506       continue;
507 
508     // FIXME: Remove the single user restriction; it's here because we're
509     //        starting with the simplest set of loops we can, and multiple
510     //        users means needing to add PHI nodes in the transform.
511     if (V->getNumUsers() > 1)
512       return std::nullopt;
513 
514     VPValue *Op1, *Op2;
515     // Walk back through recipes until we find at least one load from memory.
516     if (match(V, m_ICmp(m_VPValue(Op1), m_VPValue(Op2)))) {
517       Worklist.push_back(Op1);
518       Worklist.push_back(Op2);
519       Recipes.push_back(V->getDefiningRecipe());
520     } else if (auto *Load = dyn_cast<VPWidenLoadRecipe>(V)) {
521       // Reject masked loads for the time being; they make the exit condition
522       // more complex.
523       if (Load->isMasked())
524         return std::nullopt;
525 
526       VPValue *GEP = Load->getAddr();
527       if (!match(GEP, m_GetElementPtr(m_LiveIn(), m_VPValue())))
528         return std::nullopt;
529 
530       Recipes.push_back(Load);
531       Recipes.push_back(GEP->getDefiningRecipe());
532       GEPs.push_back(GEP->getDefiningRecipe());
533     } else
534       return std::nullopt;
535   }
536 
537   return UncountableCondition;
538 }
