540 bool VPBlockUtils::isHeader(const VPBlockBase *VPB,
541                             const VPDominatorTree &VPDT) {
542   auto *VPBB = dyn_cast<VPBasicBlock>(VPB);
543   if (!VPBB)
544     return false;
545 
546   // If VPBB is in a region R, VPBB is a loop header if R is a loop region with
547   // VPBB as its entry, i.e., free of predecessors.
548   if (auto *R = VPBB->getParent())
549     return !R->isReplicator() && !VPBB->hasPredecessors();
550 
551   // A header dominates its second predecessor (the latch), with the other
552   // predecessor being the preheader
553   return VPB->getPredecessors().size() == 2 &&
554          VPDT.dominates(VPB, VPB->getPredecessors()[1]);
555 }
556 
557 bool VPBlockUtils::isLatch(const VPBlockBase *VPB,
558                            const VPDominatorTree &VPDT) {
559   // A latch has a header as its second successor, with its other successor
560   // leaving the loop. A preheader OTOH has a header as its first (and only)
561   // successor.
562   return VPB->getNumSuccessors() == 2 &&
563          VPBlockUtils::isHeader(VPB->getSuccessors()[1], VPDT);
564 }
