566 std::optional<MemoryLocation>
567 vputils::getMemoryLocation(const VPRecipeBase &R) {
568   auto *M = dyn_cast<VPIRMetadata>(&R);
569   if (!M)
570     return std::nullopt;
571   MemoryLocation Loc;
572   // Populate noalias metadata from VPIRMetadata.
573   if (MDNode *NoAliasMD = M->getMetadata(LLVMContext::MD_noalias))
574     Loc.AATags.NoAlias = NoAliasMD;
575   if (MDNode *AliasScopeMD = M->getMetadata(LLVMContext::MD_alias_scope))
576     Loc.AATags.Scope = AliasScopeMD;
577   return Loc;
578 }
