402 SmallVector<VPRegisterUsage, 8> llvm::calculateRegisterUsageForPlan(
403     VPlan &Plan, ArrayRef<ElementCount> VFs, const TargetTransformInfo &TTI,
404     const SmallPtrSetImpl<const Value *> &ValuesToIgnore) {
405   // Each 'key' in the map opens a new interval. The values
406   // of the map are the index of the 'last seen' usage of the
407   // VPValue that is the key.
408   using IntervalMap = SmallDenseMap<VPValue *, unsigned, 16>;
409 
410   // Maps indices to recipes.
411   SmallVector<VPRecipeBase *, 64> Idx2Recipe;
412   // Marks the end of each interval.
413   IntervalMap EndPoint;
414   // Saves the list of VPValues that are used in the loop.
415   SmallPtrSet<VPValue *, 8> Ends;
416   // Saves the list of values that are used in the loop but are defined outside
417   // the loop (not including non-recipe values such as arguments and
418   // constants).
419   SmallSetVector<VPValue *, 8> LoopInvariants;
420   LoopInvariants.insert(&Plan.getVectorTripCount());
421 
422   // We scan the loop in a topological order in order and assign a number to
423   // each recipe. We use RPO to ensure that defs are met before their users. We
424   // assume that each recipe that has in-loop users starts an interval. We
425   // record every time that an in-loop value is used, so we have a list of the
426   // first occurences of each recipe and last occurrence of each VPValue.
427   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
428   ReversePostOrderTraversal<VPBlockDeepTraversalWrapper<VPBlockBase *>> RPOT(
429       LoopRegion);
430   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(RPOT)) {
431     if (!VPBB->getParent())
432       break;
433     for (VPRecipeBase &R : *VPBB) {
434       Idx2Recipe.push_back(&R);
435 
436       // Save the end location of each USE.
437       for (VPValue *U : R.operands()) {
438         auto *DefR = U->getDefiningRecipe();
439 
440         // Ignore non-recipe values such as arguments, constants, etc.
441         // FIXME: Might need some motivation why these values are ignored. If
442         // for example an argument is used inside the loop it will increase the
443         // register pressure (so shouldn't we add it to LoopInvariants).
444         auto *IRV = dyn_cast<VPIRValue>(U);
445         if (!DefR && (!IRV || !isa<Instruction>(IRV->getValue())))
446           continue;
447 
448         // If this recipe is outside the loop then record it and continue.
449         if (!DefR) {
450           LoopInvariants.insert(U);
451           continue;
452         }
453 
454         // Overwrite previous end points.
455         EndPoint[U] = Idx2Recipe.size();
456         Ends.insert(U);
457       }
458     }
459     if (VPBB == LoopRegion->getExiting()) {
460       // VPWidenIntOrFpInductionRecipes are used implicitly at the end of the
461       // exiting block, where their increment will get materialized eventually.
462       for (auto &R : LoopRegion->getEntryBasicBlock()->phis()) {
463         if (auto *WideIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(&R)) {
464           EndPoint[WideIV] = Idx2Recipe.size();
465           Ends.insert(WideIV);
466         }
467       }
468     }
469   }
470 
471   // Saves the list of intervals that end with the index in 'key'.
472   using VPValueList = SmallVector<VPValue *, 2>;
473   SmallDenseMap<unsigned, VPValueList, 16> TransposeEnds;
474 
475   // Next, we transpose the EndPoints into a multi map that holds the list of
476   // intervals that *end* at a specific location.
477   for (auto &Interval : EndPoint)
478     TransposeEnds[Interval.second].push_back(Interval.first);
479 
480   SmallPtrSet<VPValue *, 8> OpenIntervals;
481   SmallVector<VPRegisterUsage, 8> RUs(VFs.size());
482   SmallVector<SmallMapVector<unsigned, unsigned, 4>, 8> MaxUsages(VFs.size());
483 
484   LLVM_DEBUG(dbgs() << "LV(REG): Calculating max register usage:\n");
485 
486   VPTypeAnalysis TypeInfo(Plan);
487 
488   const auto &TTICapture = TTI;
489   auto GetRegUsage = [&TTICapture](Type *Ty, ElementCount VF) -> unsigned {
490     if (Ty->isTokenTy() || !VectorType::isValidElementType(Ty) ||
491         (VF.isScalable() &&
492          !TTICapture.isElementTypeLegalForScalableVector(Ty)))
493       return 0;
494     return TTICapture.getRegUsageForType(VectorType::get(Ty, VF));
495   };
496 
497   // We scan the instructions linearly and record each time that a new interval
498   // starts, by placing it in a set. If we find this value in TransposEnds then
499   // we remove it from the set. The max register usage is the maximum register
500   // usage of the recipes of the set.
501   for (unsigned int Idx = 0, Sz = Idx2Recipe.size(); Idx < Sz; ++Idx) {
502     VPRecipeBase *R = Idx2Recipe[Idx];
503 
504     // Remove all of the VPValues that end at this location.
505     VPValueList &List = TransposeEnds[Idx];
506     for (VPValue *ToRemove : List)
507       OpenIntervals.erase(ToRemove);
508 
509     // Ignore recipes that are never used within the loop and do not have side
510     // effects.
511     if (none_of(R->definedValues(),
512                 [&Ends](VPValue *Def) { return Ends.count(Def); }) &&
513         !R->mayHaveSideEffects())
514       continue;
515 
516     // Skip recipes for ignored values.
517     // TODO: Should mark recipes for ephemeral values that cannot be removed
518     // explictly in VPlan.
519     if (isa<VPSingleDefRecipe>(R) &&
520         ValuesToIgnore.contains(
521             cast<VPSingleDefRecipe>(R)->getUnderlyingValue()))
522       continue;
523 
524     // For each VF find the maximum usage of registers.
525     for (unsigned J = 0, E = VFs.size(); J < E; ++J) {
526       // Count the number of registers used, per register class, given all open
527       // intervals.
528       // Note that elements in this SmallMapVector will be default constructed
529       // as 0. So we can use "RegUsage[ClassID] += n" in the code below even if
530       // there is no previous entry for ClassID.
531       SmallMapVector<unsigned, unsigned, 4> RegUsage;
532 
533       for (auto *VPV : OpenIntervals) {
534         // Skip artificial values or values that weren't present in the original
535         // loop.
536         // TODO: Remove skipping values that weren't present in the original
537         // loop after removing the legacy
538         // LoopVectorizationCostModel::calculateRegisterUsage
539         if (isa<VPVectorPointerRecipe, VPVectorEndPointerRecipe,
540                 VPBranchOnMaskRecipe>(VPV) ||
541             match(VPV, m_ExtractLastPart(m_VPValue())))
542           continue;
543 
544         if (VFs[J].isScalar() ||
545             isa<VPCanonicalIVPHIRecipe, VPReplicateRecipe, VPDerivedIVRecipe,
546                 VPEVLBasedIVPHIRecipe, VPScalarIVStepsRecipe>(VPV) ||
547             (isa<VPInstruction>(VPV) && vputils::onlyScalarValuesUsed(VPV)) ||
548             (isa<VPReductionPHIRecipe>(VPV) &&
549              (cast<VPReductionPHIRecipe>(VPV))->isInLoop())) {
550           unsigned ClassID =
551               TTI.getRegisterClassForType(false, TypeInfo.inferScalarType(VPV));
552           // FIXME: The target might use more than one register for the type
553           // even in the scalar case.
554           RegUsage[ClassID] += 1;
555         } else {
556           unsigned ScaleFactor;
557           auto *DefR = VPV->getDefiningRecipe();
558           if (auto *ER = dyn_cast<VPExpressionRecipe>(DefR))
559             // In an expression recipe we want the maximum register usage out of
560             // its subexpressions, which means the minimum scaling factor.
561             ScaleFactor = ER->getMinVFScaleFactor();
562           else
563             // The output from scaled phis and scaled reductions actually has
564             // fewer lanes than the VF.
565             ScaleFactor = vputils::getVFScaleFactor(DefR);
566           ElementCount VF = VFs[J];
567           if (ScaleFactor > 1) {
568             VF = VFs[J].divideCoefficientBy(ScaleFactor);
569             LLVM_DEBUG(dbgs() << "LV(REG): Scaled down VF from " << VFs[J]
570                               << " to " << VF << " for " << *R << "\n";);
571           }
572 
573           Type *ScalarTy = TypeInfo.inferScalarType(VPV);
574           unsigned ClassID = TTI.getRegisterClassForType(true, ScalarTy);
575           RegUsage[ClassID] += GetRegUsage(ScalarTy, VF);
576         }
577       }
578 
579       for (const auto &Pair : RegUsage) {
580         auto &Entry = MaxUsages[J][Pair.first];
581         Entry = std::max(Entry, Pair.second);
582       }
583     }
584 
585     LLVM_DEBUG(dbgs() << "LV(REG): At #" << Idx << " Interval # "
586                       << OpenIntervals.size() << '\n');
587 
588     // Add used VPValues defined by the current recipe to the list of open
589     // intervals.
590     for (VPValue *DefV : R->definedValues())
591       if (Ends.contains(DefV))
592         OpenIntervals.insert(DefV);
593   }
594 
595   // We also search for instructions that are defined outside the loop, but are
596   // used inside the loop. We need this number separately from the max-interval
597   // usage number because when we unroll, loop-invariant values do not take
598   // more register.
599   VPRegisterUsage RU;
600   for (unsigned Idx = 0, End = VFs.size(); Idx < End; ++Idx) {
601     // Note that elements in this SmallMapVector will be default constructed
602     // as 0. So we can use "Invariant[ClassID] += n" in the code below even if
603     // there is no previous entry for ClassID.
604     SmallMapVector<unsigned, unsigned, 4> Invariant;
605 
606     for (auto *In : LoopInvariants) {
607       // FIXME: The target might use more than one register for the type
608       // even in the scalar case.
609       bool IsScalar = vputils::onlyScalarValuesUsed(In);
610 
611       ElementCount VF = IsScalar ? ElementCount::getFixed(1) : VFs[Idx];
612       unsigned ClassID = TTI.getRegisterClassForType(
613           VF.isVector(), TypeInfo.inferScalarType(In));
614       Invariant[ClassID] += GetRegUsage(TypeInfo.inferScalarType(In), VF);
615     }
616 
617     LLVM_DEBUG({
618       dbgs() << "LV(REG): VF = " << VFs[Idx] << '\n';
619       dbgs() << "LV(REG): Found max usage: " << MaxUsages[Idx].size()
620              << " item\n";
621       for (const auto &pair : MaxUsages[Idx]) {
622         dbgs() << "LV(REG): RegisterClass: "
623                << TTI.getRegisterClassName(pair.first) << ", " << pair.second
624                << " registers\n";
625       }
626       dbgs() << "LV(REG): Found invariant usage: " << Invariant.size()
627              << " item\n";
628       for (const auto &pair : Invariant) {
629         dbgs() << "LV(REG): RegisterClass: "
630                << TTI.getRegisterClassName(pair.first) << ", " << pair.second
631                << " registers\n";
632       }
633     });
634 
635     RU.LoopInvariantRegs = Invariant;
636     RU.MaxLocalUsers = MaxUsages[Idx];
637     RUs[Idx] = RU;
638   }
639 
640   return RUs;
641 }
